        <Card padding="16px 24px">
          <Breadcrumb 
            items={[
              { label: 'ĒÖł', path: '/' },
              { label: 'ņäżņĀĢ', path: '/settings' },
              { label: 'ņé¼ņÜ®ņ×É Ļ┤Ćļ”¼' } // ļ¦łņ¦Ćļ¦ē ņÜöņåīļŖö pathļź╝ ļäŻņ¦Ć ņĢŖņØī
            ]} 
          />
        </Card>
